#define THREADS_PER_BLOCK 256

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__kernel void pgain_kernel(
    const Point_Struct *p,
    const float *coord,
    float *work_mem,
    const int *center_table,
    char *switch_membership,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);
    if (i >= num) return;

    // Load point i coordinates from global memory (coord is stored as [dim][num] or similar layout based on source)
    // Source logic: coord_h[(num*i)+j] = points->p[j].coord[i] -> This means coord is [dim][num] where row is dim index
    // Actually source: for(int i=0; i<dim; i++){ for(int j=0; j<num; j++) coord_h[(num*i)+j] = points->p[j].coord[i]; }
    // So coord[index] where index = i*num + j gives coord of point j at dimension i.

    float x_cost = 0.0f;
    float current_cost = p[i].cost;
    float weight = p[i].weight;
    int assign = (int)p[i].assign;

    // Calculate distance to candidate center x
    // We need to iterate dimensions
    for (int d = 0; d < dim; d++) {
        float coord_i_d = coord[d * num + i];
        float coord_x_d = coord[d * num + x];
        float diff = coord_i_d - coord_x_d;
        x_cost += diff * diff;
    }
    x_cost *= weight;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += (x_cost - current_cost);
    } else {
        int center_idx = center_table[assign];
        work_mem[i * (K + 1) + center_idx] += (current_cost - x_cost);
    }
}
